import{_ as e,c as a,o as r,ah as o}from"./chunks/framework.RCw5T9E9.js";const p=JSON.parse('{"title":"Favorites","description":"","frontmatter":{"title":"Favorites"},"headers":[],"relativePath":"store/favorite.md","filePath":"store/favorite.md"}'),s={name:"store/favorite.md"};function n(i,t,l,h,d,g){return r(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="favorites-pinia-stores" tabindex="-1">Favorites (Pinia stores) <a class="header-anchor" href="#favorites-pinia-stores" aria-label="Permalink to &quot;Favorites (Pinia stores)&quot;">​</a></h1><p><strong>Favorite stores</strong> are a persisted list of <strong>Pinia stores</strong> for faster navigation on <strong>Stores</strong>: starred rows move <strong>to the top</strong>, show a <strong>star</strong>, and a header badge counts how many favorites match the current results.</p><p>Store overview: <a href="/qa-tools/docs/store/general.html">Overview</a>.</p><p><strong>Vue component</strong> favorites (<strong>Props</strong> tab) are separate: <a href="/qa-tools/docs/props/favorite.html">Favorites (Props)</a>.</p><hr><h2 id="add-and-remove" tabindex="-1">Add and remove <a class="header-anchor" href="#add-and-remove" aria-label="Permalink to &quot;Add and remove&quot;">​</a></h2><ul><li><strong>In the store card</strong> — header <strong>star</strong> toggles favorite.</li><li><strong>Row context menu</strong> on <strong>Stores</strong> — add/remove favorite.</li><li><strong>Stores table</strong> — click the <strong>star</strong> area on a row.</li><li><strong>Options → Pinia → Favorite Stores</strong> — browse, type names, delete, open for editing.</li></ul><p>Settings persist in the inspector profile with other options.</p><hr><h2 id="exact-names-and-wildcards" tabindex="-1">Exact names and wildcards <a class="header-anchor" href="#exact-names-and-wildcards" aria-label="Permalink to &quot;Exact names and wildcards&quot;">​</a></h2><p>Each entry defines a <strong>store name pattern</strong>.</p><ul><li>Without <strong><code>*</code></strong>, matching is <strong>exact</strong>: the star appears only for that store name.</li><li><strong><code>*</code></strong> matches any substring in the name. Example: <strong><code>use*Store</code></strong> can match <strong>useUserStore</strong>, <strong>useAuthStore</strong>, etc.</li></ul><p>Removing favorite from a row clears <strong>all</strong> rules that match that store (exact and wildcard).</p><p>Manual entry in <strong>Options</strong> uses the same wildcard rules.</p><hr><h2 id="what-is-stored" tabindex="-1">What is stored <a class="header-anchor" href="#what-is-stored" aria-label="Permalink to &quot;What is stored&quot;">​</a></h2><p>Per entry the inspector keeps:</p><ul><li><strong>display name</strong> of the store;</li><li><strong>match pattern</strong> (when using a mask);</li><li>optional <strong>session id</strong> for the matched instance;</li><li><strong>time added</strong> for display.</li></ul><p>That lets favorites apply again after the store list rebuilds.</p><hr><h2 id="matching" tabindex="-1">Matching <a class="header-anchor" href="#matching" aria-label="Permalink to &quot;Matching&quot;">​</a></h2><p>When stores load, names are compared to saved patterns:</p><ol><li><strong>exact</strong> name match;</li><li><strong>wildcard</strong> match if the entry contains <strong><code>*</code></strong>;</li><li>session hints may refine the mapping when available.</li></ol><p>If multiple stores match one mask, all matching rows can show stars.</p><hr><h2 id="sorting-and-badge" tabindex="-1">Sorting and badge <a class="header-anchor" href="#sorting-and-badge" aria-label="Permalink to &quot;Sorting and badge&quot;">​</a></h2><p>After refresh, <strong>Stores</strong> floats favorite rows <strong>up</strong>.</p><p>The header badge shows <strong>visible favorites / total saved</strong> for the current search.</p><p>Clicking the badge can open <strong>Options</strong> for Pinia favorites.</p><hr><h2 id="editing-in-options" tabindex="-1">Editing in Options <a class="header-anchor" href="#editing-in-options" aria-label="Permalink to &quot;Editing in Options&quot;">​</a></h2><p>Open an entry to change its pattern name.</p><p>Saving updates the rule; new masks take effect on the next match.</p><p>Avoid empty names — they never usefully match.</p><hr><h2 id="tips" tabindex="-1">Tips <a class="header-anchor" href="#tips" aria-label="Permalink to &quot;Tips&quot;">​</a></h2><ul><li>Favorite <strong>core</strong> stores: user, settings, UI shell.</li><li><strong>Patterns</strong> help uniform naming schemes; overly broad masks may over-select.</li><li>Favorites <strong>do not</strong> change Pinia runtime; they are local inspector metadata.</li></ul><hr><h2 id="see-also" tabindex="-1">See also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See also&quot;">​</a></h2><ul><li><a href="/qa-tools/docs/store/general.html">Store overview</a></li><li><a href="/qa-tools/docs/props/favorite.html">Favorites (Props)</a></li><li><a href="/qa-tools/docs/options/customize.html">Customize</a></li></ul>',40)])])}const m=e(s,[["render",n]]);export{p as __pageData,m as default};
